     1→package auth
     2→
     3→import (
     4→	"encoding/json"
     5→	"fmt"
     6→	"io"
     7→	"log/slog"
     8→	"net/http"
     9→	"net/url"
    10→	"strings"
    11→
    12→	"github.com/jackc/pgx/v5/pgxpool"
    13→)
    14→
    15→// OAuthHandler handles GitHub OAuth flow and session endpoints.
    16→type OAuthHandler struct {
    17→	ClientID     string
    18→	ClientSecret string
    19→	Pool         *pgxpool.Pool
    20→	Sessions     *SessionStore
    21→	States       *StateStore
    22→	Allowlist    *Allowlist
    23→	SecureCookie bool
    24→	FrontendURL  string // optional: redirect here after login/logout (for dev with separate frontend port)
    25→	HTTPClient   *http.Client
    26→}
    27→
    28→// HandleGitHubRedirect redirects to GitHub's OAuth authorize URL.
    29→func (h *OAuthHandler) HandleGitHubRedirect(w http.ResponseWriter, r *http.Request) {
    30→	state := h.States.Create()
    31→	if state == "" {
    32→		http.Error(w, "too many pending login requests", http.StatusTooManyRequests)
    33→		return
    34→	}
    35→
    36→	params := url.Values{
    37→		"client_id":    {h.ClientID},
    38→		"state":        {state},
    39→		"scope":        {"read:org"},
    40→		"redirect_uri": {callbackURL(r, h.FrontendURL)},
    41→	}
    42→	http.Redirect(w, r, "https://github.com/login/oauth/authorize?"+params.Encode(), http.StatusFound)
    43→}
    44→
    45→// HandleGitHubCallback handles the OAuth callback from GitHub.
    46→func (h *OAuthHandler) HandleGitHubCallback(w http.ResponseWriter, r *http.Request) {
    47→	// Validate state
    48→	state := r.URL.Query().Get("state")
    49→	if !h.States.Consume(state) {
    50→		http.Redirect(w, r, h.frontendURL("/login?error=invalid_state"), http.StatusFound)
    51→		return
    52→	}
    53→
    54→	code := r.URL.Query().Get("code")
    55→	if code == "" {
    56→		http.Redirect(w, r, h.frontendURL("/login?error=missing_code"), http.StatusFound)
    57→		return
    58→	}
    59→
    60→	client := h.HTTPClient
    61→	if client == nil {
    62→		client = http.DefaultClient
    63→	}
    64→
    65→	// Exchange code for access token
    66→	token, err := exchangeCode(client, h.ClientID, h.ClientSecret, code)
    67→	if err != nil {
    68→		slog.Error("github token exchange failed", "err", err)
    69→		http.Redirect(w, r, h.frontendURL("/login?error=token_exchange"), http.StatusFound)
    70→		return
    71→	}
    72→
    73→	// Fetch user info
    74→	ghUser, err := fetchGitHubUser(client, token)
    75→	if err != nil {
    76→		slog.Error("github user fetch failed", "err", err)
    77→		http.Redirect(w, r, h.frontendURL("/login?error=user_fetch"), http.StatusFound)
    78→		return
    79→	}
    80→
    81→	// Fetch user orgs
    82→	orgs, err := fetchGitHubOrgs(client, token)
    83→	if err != nil {
    84→		slog.Warn("github orgs fetch failed, proceeding without orgs", "err", err)
    85→	}
    86→
    87→	// Check allowlist
    88→	orgLogins := make([]string, len(orgs))
    89→	for i, o := range orgs {
    90→		orgLogins[i] = o.Login
    91→	}
    92→	if !h.Allowlist.IsUserAllowed(ghUser.Login, orgLogins) {
    93→		slog.Warn("login denied: user not in allowlist", "login", ghUser.Login, "orgs", orgLogins)
    94→		http.Redirect(w, r, h.frontendURL("/login?error=unauthorized"), http.StatusFound)
    95→		return
    96→	}
    97→
    98→	// Upsert user
    99→	var userID string
   100→	err = h.Pool.QueryRow(r.Context(), `
   101→		INSERT INTO users (github_id, github_login, name, avatar_url)
   102→		VALUES ($1, $2, $3, $4)
   103→		ON CONFLICT (github_id) DO UPDATE SET
   104→			github_login = EXCLUDED.github_login,
   105→			name = EXCLUDED.name,
   106→			avatar_url = EXCLUDED.avatar_url,
   107→			updated_at = NOW()
   108→		RETURNING id
   109→	`, ghUser.ID, ghUser.Login, ghUser.Name, ghUser.AvatarURL).Scan(&userID)
   110→	if err != nil {
   111→		slog.Error("user upsert failed", "err", err)
   112→		http.Redirect(w, r, h.frontendURL("/login?error=server_error"), http.StatusFound)
   113→		return
   114→	}
   115→
   116→	// Create session
   117→	cookie, expiresAt, err := h.Sessions.CreateSession(r.Context(), userID)
   118→	if err != nil {
   119→		slog.Error("session creation failed", "err", err)
   120→		http.Redirect(w, r, h.frontendURL("/login?error=server_error"), http.StatusFound)
   121→		return
   122→	}
   123→
   124→	slog.Info("user logged in", "login", ghUser.Login, "user_id", userID)
   125→
   126→	http.SetCookie(w, &http.Cookie{
   127→		Name:     "session",
   128→		Value:    cookie,
   129→		Path:     "/",
   130→		Expires:  expiresAt,
   131→		HttpOnly: true,
   132→		Secure:   h.SecureCookie,
   133→		SameSite: http.SameSiteLaxMode,
   134→	})
   135→	http.Redirect(w, r, h.frontendURL("/"), http.StatusFound)
   136→}
   137→
   138→// HandleMe returns the current user from the session context.
   139→func (h *OAuthHandler) HandleMe(w http.ResponseWriter, r *http.Request) {
   140→	u := UserFromContext(r.Context())
   141→	if u == nil {
   142→		http.Error(w, `{"error":"unauthorized"}`, http.StatusUnauthorized)
   143→		return
   144→	}
   145→	w.Header().Set("Content-Type", "application/json")
   146→	json.NewEncoder(w).Encode(u)
   147→}
   148→
   149→// HandleLogout deletes the session and clears the cookie.
   150→func (h *OAuthHandler) HandleLogout(w http.ResponseWriter, r *http.Request) {
   151→	if c, err := r.Cookie("session"); err == nil {
   152→		h.Sessions.DeleteSession(r.Context(), c.Value)
   153→	}
   154→	http.SetCookie(w, &http.Cookie{
   155→		Name:     "session",
   156→		Value:    "",
   157→		Path:     "/",
   158→		MaxAge:   -1,
   159→		HttpOnly: true,
   160→		Secure:   h.SecureCookie,
   161→		SameSite: http.SameSiteLaxMode,
   162→	})
   163→	w.WriteHeader(http.StatusOK)
   164→}
   165→
   166→// frontendURL returns a path prefixed with FrontendURL if set (for dev with separate frontend port).
   167→func (h *OAuthHandler) frontendURL(path string) string {
   168→	if h.FrontendURL != "" {
   169→		return strings.TrimRight(h.FrontendURL, "/") + path
   170→	}
   171→	return path
   172→}
   173→
   174→// RequireSession is middleware that loads the user from the session cookie into context.
   175→func (h *OAuthHandler) RequireSession(next http.Handler) http.Handler {
   176→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
   177→		c, err := r.Cookie("session")
   178→		if err != nil {
   179→			http.Error(w, `{"error":"unauthorized"}`, http.StatusUnauthorized)
   180→			return
   181→		}
   182→		u, err := h.Sessions.ValidateSession(r.Context(), c.Value)
   183→		if err != nil {
   184→			http.Error(w, `{"error":"unauthorized"}`, http.StatusUnauthorized)
   185→			return
   186→		}
   187→		next.ServeHTTP(w, r.WithContext(WithUser(r.Context(), u)))
   188→	})
   189→}
   190→
   191→// --- GitHub API helpers ---
   192→
   193→type githubUser struct {
   194→	ID        int64  `json:"id"`
   195→	Login     string `json:"login"`
   196→	Name      string `json:"name"`
   197→	AvatarURL string `json:"avatar_url"`
   198→}
   199→
   200→type githubOrg struct {
   201→	Login string `json:"login"`
   202→}
   203→
   204→func exchangeCode(client *http.Client, clientID, clientSecret, code string) (string, error) {
   205→	data := url.Values{
   206→		"client_id":     {clientID},
   207→		"client_secret": {clientSecret},
   208→		"code":          {code},
   209→	}
   210→	req, _ := http.NewRequest(http.MethodPost, "https://github.com/login/oauth/access_token", strings.NewReader(data.Encode()))
   211→	req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
   212→	req.Header.Set("Accept", "application/json")
   213→
   214→	resp, err := client.Do(req)
   215→	if err != nil {
   216→		return "", fmt.Errorf("token request: %w", err)
   217→	}
   218→	defer resp.Body.Close()
   219→
   220→	var result struct {
   221→		AccessToken string `json:"access_token"`
   222→		Error       string `json:"error"`
   223→	}
   224→	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
   225→		return "", fmt.Errorf("decode token response: %w", err)
   226→	}
   227→	if result.Error != "" {
   228→		return "", fmt.Errorf("github error: %s", result.Error)
   229→	}
   230→	if result.AccessToken == "" {
   231→		return "", fmt.Errorf("empty access token")
   232→	}
   233→	return result.AccessToken, nil
   234→}
   235→
   236→func fetchGitHubUser(client *http.Client, token string) (*githubUser, error) {
   237→	req, _ := http.NewRequest(http.MethodGet, "https://api.github.com/user", nil)
   238→	req.Header.Set("Authorization", "Bearer "+token)
   239→	req.Header.Set("Accept", "application/json")
   240→
   241→	resp, err := client.Do(req)
   242→	if err != nil {
   243→		return nil, err
   244→	}
   245→	defer resp.Body.Close()
   246→	if resp.StatusCode != http.StatusOK {
   247→		body, _ := io.ReadAll(resp.Body)
   248→		return nil, fmt.Errorf("github /user returned %d: %s", resp.StatusCode, body)
   249→	}
   250→
   251→	var u githubUser
   252→	if err := json.NewDecoder(resp.Body).Decode(&u); err != nil {
   253→		return nil, err
   254→	}
   255→	return &u, nil
   256→}
   257→
   258→func fetchGitHubOrgs(client *http.Client, token string) ([]githubOrg, error) {
   259→	req, _ := http.NewRequest(http.MethodGet, "https://api.github.com/user/orgs", nil)
   260→	req.Header.Set("Authorization", "Bearer "+token)
   261→	req.Header.Set("Accept", "application/json")
   262→
   263→	resp, err := client.Do(req)
   264→	if err != nil {
   265→		return nil, err
   266→	}
   267→	defer resp.Body.Close()
   268→	if resp.StatusCode != http.StatusOK {
   269→		return nil, fmt.Errorf("github /user/orgs returned %d", resp.StatusCode)
   270→	}
   271→
   272→	var orgs []githubOrg
   273→	if err := json.NewDecoder(resp.Body).Decode(&orgs); err != nil {
   274→		return nil, err
   275→	}
   276→	return orgs, nil
   277→}
   278→
   279→func callbackURL(r *http.Request, frontendURL string) string {
   280→	// When a frontend URL is configured (dev with separate frontend port),
   281→	// use it so the GitHub callback goes through the frontend proxy and the
   282→	// session cookie is set on the correct origin.
   283→	if frontendURL != "" {
   284→		return strings.TrimRight(frontendURL, "/") + "/auth/github/callback"
   285→	}
   286→	scheme := "https"
   287→	if r.TLS == nil {
   288→		scheme = "http"
   289→	}
   290→	if fwd := r.Header.Get("X-Forwarded-Proto"); fwd != "" {
   291→		scheme = fwd
   292→	}
   293→	return scheme + "://" + r.Host + "/auth/github/callback"
   294→}
   295→
   296→// DevUser returns a fake user for NO_AUTH development mode.
   297→func DevUser() *User {
   298→	return &User{
   299→		ID:          "00000000-0000-0000-0000-000000000000",
   300→		GitHubID:    0,
   301→		GitHubLogin: "dev",
   302→		Name:        "Dev User",
   303→		AvatarURL:   "",
   304→	}
   305→}
   306→
   307→// HandleMeDev returns a hardcoded dev user (for NO_AUTH mode).
   308→func HandleMeDev(w http.ResponseWriter, r *http.Request) {
   309→	w.Header().Set("Content-Type", "application/json")
   310→	json.NewEncoder(w).Encode(DevUser())
   311→}
   312→
   313→// DevSession is middleware that injects a fake dev user (for NO_AUTH mode).
   314→func DevSession(next http.Handler) http.Handler {
   315→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
   316→		ctx := WithUser(r.Context(), DevUser())
   317→		next.ServeHTTP(w, r.WithContext(ctx))
   318→	})
   319→}
