    10→
    11→const defaultNpmBaseURL = "https://registry.npmjs.org"
    12→
    13→// npmPackage represents the top-level response from the npm registry API.
    14→type npmPackage struct {
    15→	Name string `json:"name"`
    16→	// Time maps version strings to their publish timestamps.
    17→	// Also contains "created" and "modified" keys which we skip.
    18→	Time map[string]string `json:"time"`
    19→}
    20→
    21→// NpmSource polls the npm registry API for package releases.
    22→type NpmSource struct {
    23→	client   *http.Client
    24→	pkg      string
    25→	baseURL  string
    26→	sourceID string
    27→}
    28→
    29→func NewNpmSource(client *http.Client, pkg string, sourceID string) *NpmSource {
    30→	return &NpmSource{
    31→		client:   client,
    32→		pkg:      pkg,
    33→		baseURL:  defaultNpmBaseURL,
    34→		sourceID: sourceID,
    35→	}
    36→}
    37→
    38→func (s *NpmSource) Name() string    { return "npm" }
    39→func (s *NpmSource) SourceID() string { return s.sourceID }
    40→
    41→func (s *NpmSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
    42→	url := fmt.Sprintf("%s/%s", s.baseURL, s.pkg)
    43→
    44→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
    45→	if err != nil {
    46→		return nil, fmt.Errorf("create request: %w", err)
    47→	}
    48→	req.Header.Set("Accept", "application/json")
    49→
    50→	resp, err := s.client.Do(req)
    51→	if err != nil {
    52→		return nil, fmt.Errorf("fetch releases: %w", err)
    53→	}
    54→	defer resp.Body.Close()
    55→
    56→	if resp.StatusCode != http.StatusOK {
    57→		return nil, httpStatusError(resp)
    58→	}
    59→
    60→	var pkg npmPackage
    61→	if err := json.NewDecoder(resp.Body).Decode(&pkg); err != nil {
    62→		return nil, fmt.Errorf("decode response: %w", err)
    63→	}
    64→
    65→	results := make([]IngestionResult, 0, len(pkg.Time))
    66→	for version, publishedAt := range pkg.Time {
    67→		// Skip metadata keys that aren't real versions.
    68→		if version == "created" || version == "modified" {
    69→			continue
    70→		}
    71→		if version == "" {
    72→			continue
    73→		}
    74→
    75→		var ts time.Time
    76→		if publishedAt != "" {
    77→			parsed, err := time.Parse(time.RFC3339, publishedAt)
    78→			if err == nil {
    79→				ts = parsed
    80→			}
    81→		}
    82→
    83→		releaseURL := fmt.Sprintf("https://www.npmjs.com/package/%s/v/%s", s.pkg, version)
    84→
    85→		results = append(results, IngestionResult{
    86→			Repository: s.pkg,
    87→			RawVersion: version,
    88→			Changelog:  "",
    89→			Metadata: map[string]string{
    90→				"release_url": releaseURL,
    91→			},
    92→			Timestamp: ts,
    93→		})
    94→	}
    95→	return results, nil
    96→}
    97→

