     1→package onboard
     2→
     3→import (
     4→	"context"
     5→	"encoding/base64"
     6→	"encoding/json"
     7→	"fmt"
     8→	"net/http"
     9→	"os"
    10→	"path/filepath"
    11→	"strings"
    12→)
    13→
    14→// DependencyFile holds the path and decoded content of a dependency manifest.
    15→type DependencyFile struct {
    16→	Path    string `json:"path"`
    17→	Content string `json:"content"`
    18→}
    19→
    20→// depFileNames lists known dependency/manifest file names.
    21→var depFileNames = map[string]bool{
    22→	"go.mod":               true,
    23→	"go.sum":               false, // skip, too large and low value
    24→	"package.json":         true,
    25→	"package-lock.json":    false,
    26→	"yarn.lock":            false,
    27→	"requirements.txt":     true,
    28→	"Pipfile":              true,
    29→	"pyproject.toml":       true,
    30→	"Cargo.toml":           true,
    31→	"Gemfile":              true,
    32→	"pom.xml":              true,
    33→	"build.gradle":         true,
    34→	"build.gradle.kts":     true,
    35→	"Dockerfile":           true,
    36→	"docker-compose.yml":   true,
    37→	"docker-compose.yaml":  true,
    38→}
    39→
    40→// Scanner fetches dependency files from a GitHub repo via the API.
    41→type Scanner struct {
    42→	client  *http.Client
    43→	baseURL string
    44→	token   string
    45→}
    46→
    47→// NewScanner creates a Scanner. If token is empty, it reads GITHUB_TOKEN from env.
    48→func NewScanner(client *http.Client, baseURL, token string) *Scanner {
    49→	if token == "" {
    50→		token = os.Getenv("GITHUB_TOKEN")
    51→	}
    52→	if baseURL == "" {
    53→		baseURL = "https://api.github.com"
    54→	}
    55→	return &Scanner{client: client, baseURL: baseURL, token: token}
    56→}
    57→
    58→// ParseRepoURL extracts owner and repo from various GitHub URL formats.
    59→func ParseRepoURL(raw string) (owner, repo string, err error) {
    60→	raw = strings.TrimSpace(raw)
    61→	if raw == "" {
    62→		return "", "", fmt.Errorf("empty repo URL")
    63→	}
    64→	// Strip common prefixes
    65→	raw = strings.TrimPrefix(raw, "https://")
    66→	raw = strings.TrimPrefix(raw, "http://")
    67→	raw = strings.TrimPrefix(raw, "github.com/")
    68→	raw = strings.TrimSuffix(raw, ".git")
    69→	raw = strings.TrimSuffix(raw, "/")
    70→
    71→	parts := strings.SplitN(raw, "/", 3)
    72→	if len(parts) < 2 || parts[0] == "" || parts[1] == "" {
    73→		return "", "", fmt.Errorf("invalid repo URL: expected 'owner/repo', got %q", raw)
    74→	}
    75→	return parts[0], parts[1], nil
    76→}
    77→
    78→// FetchDependencyFiles fetches the repo tree, identifies dependency files, and returns their contents.
    79→func (s *Scanner) FetchDependencyFiles(ctx context.Context, owner, repo string) ([]DependencyFile, error) {
    80→	branch, err := s.getDefaultBranch(ctx, owner, repo)
    81→	if err != nil {
    82→		return nil, fmt.Errorf("get default branch: %w", err)
    83→	}
    84→
    85→	tree, err := s.getTree(ctx, owner, repo, branch)
    86→	if err != nil {
    87→		return nil, fmt.Errorf("get tree: %w", err)
    88→	}
    89→
    90→	// Filter to dependency files
    91→	var depPaths []string
    92→	for _, entry := range tree {
    93→		if entry.Type != "blob" {
    94→			continue
    95→		}
    96→		base := filepath.Base(entry.Path)
    97→		if depFileNames[base] {
    98→			depPaths = append(depPaths, entry.Path)
    99→		}
   100→	}
   101→
   102→	// Fetch contents
   103→	var files []DependencyFile
   104→	for _, path := range depPaths {
   105→		content, err := s.getFileContent(ctx, owner, repo, path)
   106→		if err != nil {
   107→			return nil, fmt.Errorf("fetch %s: %w", path, err)
   108→		}
   109→		files = append(files, DependencyFile{Path: path, Content: content})
   110→	}
   111→	return files, nil
   112→}
   113→
   114→type treeEntry struct {
   115→	Path string `json:"path"`
   116→	Type string `json:"type"`
   117→}
   118→
   119→func (s *Scanner) getDefaultBranch(ctx context.Context, owner, repo string) (string, error) {
   120→	url := fmt.Sprintf("%s/repos/%s/%s", s.baseURL, owner, repo)
   121→	var result struct {
   122→		DefaultBranch string `json:"default_branch"`
   123→	}
   124→	if err := s.doGet(ctx, url, &result); err != nil {
   125→		return "", err
   126→	}
   127→	return result.DefaultBranch, nil
   128→}
   129→
   130→func (s *Scanner) getTree(ctx context.Context, owner, repo, branch string) ([]treeEntry, error) {
   131→	url := fmt.Sprintf("%s/repos/%s/%s/git/trees/%s?recursive=1", s.baseURL, owner, repo, branch)
   132→	var result struct {
   133→		Tree []treeEntry `json:"tree"`
   134→	}
   135→	if err := s.doGet(ctx, url, &result); err != nil {
   136→		return nil, err
   137→	}
   138→	return result.Tree, nil
   139→}
   140→
   141→func (s *Scanner) getFileContent(ctx context.Context, owner, repo, path string) (string, error) {
   142→	url := fmt.Sprintf("%s/repos/%s/%s/contents/%s", s.baseURL, owner, repo, path)
   143→	var result struct {
   144→		Content  string `json:"content"`
   145→		Encoding string `json:"encoding"`
   146→	}
   147→	if err := s.doGet(ctx, url, &result); err != nil {
   148→		return "", err
   149→	}
   150→	if result.Encoding == "base64" {
   151→		decoded, err := base64.StdEncoding.DecodeString(strings.ReplaceAll(result.Content, "\n", ""))
   152→		if err != nil {
   153→			return "", fmt.Errorf("decode base64: %w", err)
   154→		}
   155→		return string(decoded), nil
   156→	}
   157→	return result.Content, nil
   158→}
   159→
   160→func (s *Scanner) doGet(ctx context.Context, url string, out any) error {
   161→	req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
   162→	if err != nil {
   163→		return err
   164→	}
   165→	if s.token != "" {
   166→		req.Header.Set("Authorization", "Bearer "+s.token)
   167→	}
   168→	req.Header.Set("Accept", "application/vnd.github+json")
   169→	resp, err := s.client.Do(req)
   170→	if err != nil {
   171→		return err
   172→	}
   173→	defer resp.Body.Close()
   174→	if resp.StatusCode != http.StatusOK {
   175→		return fmt.Errorf("GitHub API returned %d for %s", resp.StatusCode, url)
   176→	}
   177→	return json.NewDecoder(resp.Body).Decode(out)
   178→}
