    24→
    25→// OnboardApplyResult holds the outcome of applying scan selections.
    26→type OnboardApplyResult struct {
    27→	CreatedProjects []models.Project `json:"created_projects"`
    28→	CreatedSources  []models.Source  `json:"created_sources"`
    29→	Skipped         []string         `json:"skipped"`
    30→}
    31→
    32→// OnboardStore defines the data access interface for onboarding operations.
    33→type OnboardStore interface {
    34→	CreateOnboardScan(ctx context.Context, repoURL string) (*models.OnboardScan, error)
    35→	GetOnboardScan(ctx context.Context, id string) (*models.OnboardScan, error)
    36→	UpdateOnboardScanStatus(ctx context.Context, id, status string, results json.RawMessage, scanErr string) error
    37→	ActiveScanForRepo(ctx context.Context, repoURL string) (*models.OnboardScan, error)
    38→	ApplyOnboardScan(ctx context.Context, scanID string, selections []OnboardSelection) (*OnboardApplyResult, error)
    39→}
    40→
    41→// OnboardHandler handles HTTP requests for repo onboarding.
    42→type OnboardHandler struct {
    43→	store OnboardStore
    44→}
    45→
    46→// NewOnboardHandler creates a new OnboardHandler.
    47→func NewOnboardHandler(store OnboardStore) *OnboardHandler {
    48→	return &OnboardHandler{store: store}
    49→}
    50→
    51→// Scan creates a new dependency scan for a GitHub repo.
    52→func (h *OnboardHandler) Scan(w http.ResponseWriter, r *http.Request) {
    53→	var input struct {
    54→		RepoURL string `json:"repo_url"`
    55→	}
    56→	if err := DecodeJSON(r, &input); err != nil {
    57→		RespondError(w, r, http.StatusBadRequest, "bad_request", err.Error())
    58→		return
    59→	}
    60→
    61→	// Normalize the repo URL
    62→	owner, repo, err := onboard.ParseRepoURL(input.RepoURL)
    63→	if err != nil || strings.TrimSpace(input.RepoURL) == "" {
    64→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "Invalid or empty repo URL")
    65→		return
    66→	}
    67→	normalizedURL := fmt.Sprintf("%s/%s", owner, repo)
    68→
    69→	// Check for active scan
    70→	active, err := h.store.ActiveScanForRepo(r.Context(), normalizedURL)
    71→	if err != nil {
    72→		RespondError(w, r, http.StatusInternalServerError, "internal_error", err.Error())
    73→		return
    74→	}
    75→	if active != nil {
    76→		RespondJSON(w, r, http.StatusConflict, active)
    77→		return
    78→	}
    79→
    80→	scan, err := h.store.CreateOnboardScan(r.Context(), normalizedURL)
    81→	if err != nil {
    82→		RespondError(w, r, http.StatusInternalServerError, "internal_error", err.Error())
    83→		return
    84→	}
    85→	RespondJSON(w, r, http.StatusCreated, scan)
    86→}
    87→
    88→// GetScan returns a single scan by ID.
    89→func (h *OnboardHandler) GetScan(w http.ResponseWriter, r *http.Request) {
    90→	id := r.PathValue("id")
    91→	scan, err := h.store.GetOnboardScan(r.Context(), id)
    92→	if err != nil {
    93→		if errors.Is(err, pgx.ErrNoRows) {
    94→			RespondError(w, r, http.StatusNotFound, "not_found", "Scan not found")
    95→			return
    96→		}
    97→		RespondError(w, r, http.StatusInternalServerError, "internal_error", err.Error())
    98→		return
    99→	}
   100→	RespondJSON(w, r, http.StatusOK, scan)
   101→}
   102→
   103→// Apply creates projects and sources from the user's selections.
   104→func (h *OnboardHandler) Apply(w http.ResponseWriter, r *http.Request) {
   105→	id := r.PathValue("id")
   106→	var input struct {
   107→		Selections []OnboardSelection `json:"selections"`
   108→	}
   109→	if err := DecodeJSON(r, &input); err != nil {
   110→		RespondError(w, r, http.StatusBadRequest, "bad_request", err.Error())
   111→		return
   112→	}
   113→
   114→	// Validate selections
   115→	for i, sel := range input.Selections {
   116→		hasProjectID := sel.ProjectID != ""
   117→		hasNewName := sel.NewProjectName != ""
   118→		if hasProjectID == hasNewName {
   119→			RespondError(w, r, http.StatusBadRequest, "validation_error",
   120→				fmt.Sprintf("selection[%d]: exactly one of project_id or new_project_name must be set", i))
   121→			return
   122→		}
   123→	}
   124→
   125→	result, err := h.store.ApplyOnboardScan(r.Context(), id, input.Selections)
   126→	if err != nil {
   127→		RespondError(w, r, http.StatusInternalServerError, "internal_error", err.Error())
   128→		return
   129→	}
   130→	RespondJSON(w, r, http.StatusOK, result)
   131→}
