    30→// DependencyExtractor uses an LLM to extract dependencies from file contents.
    31→// Supports both Gemini and OpenAI providers.
    32→type DependencyExtractor struct {
    33→	provider string // "gemini" or "openai"
    34→	model    string
    35→
    36→	// Gemini
    37→	geminiClient *genai.Client
    38→
    39→	// OpenAI
