   103→// Extract sends file contents to the configured LLM and returns parsed dependencies.
   104→func (e *DependencyExtractor) Extract(ctx context.Context, files []DependencyFile) ([]models.ScannedDependency, error) {
   105→	prompt := BuildExtractionPrompt(files)
   106→
   107→	var text string
   108→	var err error
   109→
   110→	switch e.provider {
   111→	case "gemini":
   112→		text, err = e.extractGemini(ctx, prompt)
   113→	case "openai":
   114→		text, err = e.extractOpenAI(ctx, prompt)
   115→	default:
   116→		return nil, fmt.Errorf("unknown provider: %s", e.provider)
   117→	}
   118→
   119→	if err != nil {
   120→		return nil, err
   121→	}
   122→
   123→	return ParseDependencies([]byte(text))
   124→}
