   126→func (e *DependencyExtractor) extractGemini(ctx context.Context, prompt string) (string, error) {
   127→	resp, err := e.geminiClient.Models.GenerateContent(ctx, e.model, []*genai.Content{genai.NewContentFromText(prompt, "user")}, &genai.GenerateContentConfig{
   128→		SystemInstruction: genai.NewContentFromText(extractionSystemPrompt, "user"),
   129→		Temperature:       genai.Ptr(float32(0.1)),
   130→	})
   131→	if err != nil {
   132→		return "", fmt.Errorf("generate content: %w", err)
   133→	}
   134→
   135→	if len(resp.Candidates) == 0 || len(resp.Candidates[0].Content.Parts) == 0 {
   136→		return "", fmt.Errorf("empty response from Gemini")
   137→	}
   138→
   139→	return resp.Candidates[0].Content.Parts[0].Text, nil
   140→}
