   160→// DockerHub handles GET /discover/dockerhub — searches Docker Hub repositories.
   161→func (h *DiscoverHandler) DockerHub(w http.ResponseWriter, r *http.Request) {
   162→	q := r.URL.Query().Get("q")
   163→	if q == "" {
   164→		q = "nginx"
   165→	}
   166→
   167→	cacheKey := fmt.Sprintf("dockerhub:%s", q)
   168→	if items, ok := h.getCached(cacheKey); ok {
   169→		RespondJSON(w, r, http.StatusOK, items)
   170→		return
   171→	}
   172→
   173→	u, _ := url.Parse(h.dockerHubURL + "/v2/search/repositories/")
   174→	params := url.Values{}
   175→	params.Set("query", q)
   176→	params.Set("page_size", "25")
   177→	u.RawQuery = params.Encode()
   178→
   179→	req, err := http.NewRequestWithContext(r.Context(), http.MethodGet, u.String(), nil)
   180→	if err != nil {
   181→		RespondError(w, r, http.StatusInternalServerError, "request_error", "failed to build Docker Hub request")
   182→		return
   183→	}
   184→	resp, err := h.client.Do(req)
   185→	if err != nil {
   186→		RespondError(w, r, http.StatusBadGateway, "upstream_error", "failed to reach Docker Hub API")
   187→		return
   188→	}
   189→	defer resp.Body.Close()
   190→
   191→	if resp.StatusCode != http.StatusOK {
   192→		RespondError(w, r, http.StatusBadGateway, "upstream_error", fmt.Sprintf("Docker Hub API returned %d", resp.StatusCode))
   193→		return
   194→	}
   195→
   196→	var dhResp struct {
   197→		Results []struct {
   198→			RepoName         string `json:"repo_name"`
   199→			ShortDescription string `json:"short_description"`
   200→			StarCount        int    `json:"star_count"`
   201→			IsOfficial       bool   `json:"is_official"`
   202→		} `json:"results"`
   203→	}
   204→	if err := json.NewDecoder(resp.Body).Decode(&dhResp); err != nil {
   205→		RespondError(w, r, http.StatusInternalServerError, "decode_error", "failed to parse Docker Hub response")
   206→		return
   207→	}
   208→
   209→	items := make([]DiscoverItem, 0, len(dhResp.Results))
   210→	for _, repo := range dhResp.Results {
   211→		name := repo.RepoName
   212→		fullName := repo.RepoName
   213→		if repo.IsOfficial {
   214→			fullName = "library/" + repo.RepoName
   215→		}
   216→		hubURL := fmt.Sprintf("https://hub.docker.com/r/%s", repo.RepoName)
   217→		if repo.IsOfficial {
   218→			hubURL = fmt.Sprintf("https://hub.docker.com/_/%s", repo.RepoName)
   219→		}
   220→		items = append(items, DiscoverItem{
   221→			Name:        name,
   222→			FullName:    fullName,
   223→			Description: repo.ShortDescription,
   224→			Stars:       repo.StarCount,
   225→			URL:         hubURL,
   226→			Provider:    "dockerhub",
   227→		})
   228→	}
   229→
   230→	h.setCache(cacheKey, items)
   231→	RespondJSON(w, r, http.StatusOK, items)
   232→}
