    13→
    14→type KeyStore interface {
    15→	ValidateKey(ctx context.Context, rawKey string) (bool, error)
    16→	TouchKeyUsage(ctx context.Context, rawKey string)
    17→}
    18→
    19→// SessionValidator validates a session cookie and returns the user.
    20→type SessionValidator interface {
    21→	ValidateSession(ctx context.Context, cookie string) (*auth.User, error)
    22→}
    23→
    24→func Auth(store KeyStore, sessions SessionValidator) Middleware {
    25→	return func(next http.Handler) http.Handler {
    26→		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    27→			// Try Bearer token first
    28→			if header := r.Header.Get("Authorization"); strings.HasPrefix(header, "Bearer ") {
    29→				rawKey := strings.TrimPrefix(header, "Bearer ")
    30→				valid, err := store.ValidateKey(r.Context(), rawKey)
    31→				if err != nil || !valid {
    32→					RespondError(w, r, http.StatusUnauthorized, "unauthorized", "Invalid API key")
    33→					return
    34→				}
    35→				go store.TouchKeyUsage(context.Background(), rawKey)
    36→				next.ServeHTTP(w, r)
    37→				return
    38→			}
    39→
    40→			// Try session cookie
    41→			if sessions != nil {
    42→				if c, err := r.Cookie("session"); err == nil {
    43→					u, err := sessions.ValidateSession(r.Context(), c.Value)
    44→					if err == nil {
    45→						next.ServeHTTP(w, r.WithContext(auth.WithUser(r.Context(), u)))
    46→						return
    47→					}
    48→				}
    49→			}
    50→
    51→			RespondError(w, r, http.StatusUnauthorized, "unauthorized", "Missing API key")
    52→		})
    53→	}
    54→}
    55→
    56→func RateLimit(rps float64, burst int) Middleware {
    57→	var mu sync.Mutex
    58→	limiters := make(map[string]*rate.Limiter)
    59→	getLimiter := func(key string) *rate.Limiter {
    60→		mu.Lock()
    61→		defer mu.Unlock()
    62→		if lim, ok := limiters[key]; ok {
    63→			return lim
    64→		}
    65→		lim := rate.NewLimiter(rate.Limit(rps), burst)
    66→		limiters[key] = lim
    67→		return lim
    68→	}
    69→	return func(next http.Handler) http.Handler {
    70→		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    71→			key := r.RemoteAddr
    72→			if auth := r.Header.Get("Authorization"); strings.HasPrefix(auth, "Bearer ") {
    73→				key = strings.TrimPrefix(auth, "Bearer ")
    74→			}
    75→			lim := getLimiter(key)
    76→			if !lim.Allow() {
    77→				w.Header().Set("Retry-After", "1")
    78→				RespondError(w, r, http.StatusTooManyRequests, "rate_limited", "Too many requests")
    79→				return
    80→			}
    81→			next.ServeHTTP(w, r)
    82→		})
    83→	}
    84→}
