    11→function formatStars(count: number): string {
    12→  if (count >= 1000) {
    13→    const k = count / 1000;
    14→    return k >= 10 ? `${Math.round(k)}k` : `${Math.round(k * 10) / 10}k`;
    15→  }
    16→  return String(count);
    17→}
