    19→export function DiscoverySection() {
    20→  const [trackingIds, setTrackingIds] = useState<Set<string>>(new Set());
    21→  const [paused, setPaused] = useState(false);
    22→
    23→  const { data: githubData, isLoading } = useSWR(
    24→    "discover-github",
    25→    () => discover.github(),
    26→    { revalidateOnFocus: false },
    27→  );
    28→
    29→  const { data: projectsData } = useSWR(
    30→    "projects-list",
    31→    () => projects.list(1, 200),
    32→    { revalidateOnFocus: false },
    33→  );
    34→
    35→  const trackedNames = useMemo(
    36→    () =>
    37→      new Set(
    38→        (projectsData?.data ?? []).flatMap((p) => [
    39→          p.name,
    40→          p.name.split("/").pop()!,
    41→        ]),
    42→      ),
    43→    [projectsData],
    44→  );
    45→
    46→  const allItems = useMemo(() => githubData?.data ?? [], [githubData]);
    47→
    48→  const isTracked = useCallback(
    49→    (item: DiscoverItem) =>
    50→      trackedNames.has(item.full_name) || trackedNames.has(item.name),
    51→    [trackedNames],
    52→  );
    53→
    54→  const handleTrack = useCallback(
    55→    async (item: DiscoverItem) => {
    56→      const key = item.full_name;
    57→      setTrackingIds((prev) => new Set(prev).add(key));
    58→      try {
    59→        const projRes = await projects.create({
    60→          name: item.full_name,
    61→          description: item.description,
    62→        });
    63→        const project = projRes.data;
    64→
    65→        const provider = item.provider === "github" ? "github" : "dockerhub";
    66→        const sourceRes = await sources.create(project.id, {
    67→          provider,
    68→          repository: item.full_name,
    69→          poll_interval_seconds: 86400,
    70→          enabled: true,
    71→        });
    72→
    73→        await sources.poll(sourceRes.data.id);
    74→        await mutate("projects-list");
    75→        await mutate("projects-for-dashboard");
    76→      } catch (err: unknown) {
    77→        const msg =
    78→          err instanceof Error ? err.message : "Failed to track project";
    79→        alert(msg);
    80→      } finally {
    81→        setTrackingIds((prev) => {
    82→          const next = new Set(prev);
    83→          next.delete(key);
    84→          return next;
    85→        });
    86→      }
    87→    },
    88→    [],
    89→  );
    90→
    91→  if (isLoading) {
    92→    return (
    93→      <div
    94→        className="rounded-lg bg-white px-5 py-4"
    95→        style={{ border: "1px solid #e8e8e5" }}
    96→      >
    97→        <div className="flex items-center gap-3">
    98→          <span
    99→            style={{
   100→              fontFamily: "var(--font-fraunces)",
   101→              fontSize: "14px",
   102→              fontWeight: 600,
   103→              color: "#111113",
   104→            }}
   105→          >
   106→            Trending
   107→          </span>
   108→          <div className="flex gap-3 overflow-hidden">
   109→            {Array.from({ length: 6 }).map((_, i) => (
   110→              <div
   111→                key={i}
   112→                className="h-8 w-48 flex-shrink-0 animate-pulse rounded-full"
   113→                style={{ backgroundColor: "#f0f0ed" }}
   114→              />
   115→            ))}
   116→          </div>
   117→        </div>
   118→      </div>
   119→    );
   120→  }
   121→
   122→  if (allItems.length === 0) return null;
   123→
   124→  return (
   125→    <div
   126→      className="rounded-lg bg-white"
   127→      style={{ border: "1px solid #e8e8e5", overflow: "hidden" }}
   128→    >
   129→      <div className="flex items-center gap-4 px-5 py-3">
   130→        {/* Label */}
   131→        <span
   132→          className="flex-shrink-0"
   133→          style={{
   134→            fontFamily: "var(--font-fraunces)",
   135→            fontSize: "14px",
   136→            fontWeight: 600,
   137→            color: "#111113",
   138→          }}
   139→        >
   140→          Trending
   141→        </span>
   142→
   143→        {/* Marquee container */}
   144→        <div
   145→          className="relative flex-1 overflow-hidden"
   146→          onMouseEnter={() => setPaused(true)}
   147→          onMouseLeave={() => setPaused(false)}
   148→        >
   149→          {/* Fade edges */}
   150→          <div
   151→            className="pointer-events-none absolute left-0 top-0 z-10 h-full w-8"
   152→            style={{
   153→              background:
   154→                "linear-gradient(to right, white, transparent)",
   155→            }}
   156→          />
   157→          <div
   158→            className="pointer-events-none absolute right-0 top-0 z-10 h-full w-8"
   159→            style={{
   160→              background:
   161→                "linear-gradient(to left, white, transparent)",
   162→            }}
   163→          />
   164→
   165→          {/* Scrolling track — duplicated for seamless loop */}
   166→          <div
   167→            className="flex gap-2.5"
   168→            style={{
   169→              animationName: "marquee",
   170→              animationDuration: `${Math.max(allItems.length * 6, 60)}s`,
   171→              animationTimingFunction: "linear",
   172→              animationIterationCount: "infinite",
   173→              animationPlayState: paused ? "paused" : "running",
   174→              width: "max-content",
   175→            }}
   176→          >
   177→            {[...allItems, ...allItems].map((item, idx) => {
   178→              const tracked = isTracked(item);
   179→              const tracking = trackingIds.has(item.full_name);
   180→
   181→              return (
   182→                <MarqueeChip
   183→                  key={`${item.full_name}-${idx}`}
   184→                  item={item}
   185→                  tracked={tracked}
   186→                  tracking={tracking}
   187→                  onTrack={handleTrack}
   188→                />
   189→              );
   190→            })}
   191→          </div>
   192→        </div>
   193→      </div>
   194→
   195→      {/* Keyframes injected via style tag */}
   196→      <style>{`
   197→        @keyframes marquee {
   198→          0% { transform: translateX(0); }
   199→          100% { transform: translateX(-50%); }
   200→        }
   201→      `}</style>
   202→    </div>
   203→  );
   204→}
   205→
   206→/* ------------------------------------------------------------------ */
   207→
   208→function MarqueeChip({
   209→  item,
   210→  tracked,
   211→  tracking,
   212→  onTrack,
   213→}: {
   214→  item: DiscoverItem;
   215→  tracked: boolean;
   216→  tracking: boolean;
   217→  onTrack: (item: DiscoverItem) => void;
   218→}) {
   219→  const ProviderIcon =
   220→    item.provider === "github" ? FaGithub : FaDocker;
   221→
   222→  if (tracked) {
   223→    return (
   224→      <span
   225→        className="inline-flex flex-shrink-0 items-center gap-1.5 rounded-full px-3 py-1.5"
   226→        style={{
   227→          fontFamily: "var(--font-dm-sans)",
   228→          fontSize: "12px",
   229→          color: "#16a34a",
   230→          backgroundColor: "#f0fdf4",
   231→          border: "1px solid #bbf7d0",
   232→          whiteSpace: "nowrap",
   233→        }}
   234→      >
   235→        <ProviderIcon className="h-3 w-3" style={{ color: "#6b7280" }} />
   236→        {item.full_name}
   237→        <Check className="h-3 w-3" />
   238→      </span>
   239→    );
   240→  }
   241→
   242→  return (
   243→    <button
   244→      onClick={() => onTrack(item)}
   245→      disabled={tracking}
   246→      className="inline-flex flex-shrink-0 items-center gap-1.5 rounded-full px-3 py-1.5 transition-all hover:shadow-sm disabled:opacity-70"
   247→      style={{
   248→        fontFamily: "var(--font-dm-sans)",
   249→        fontSize: "12px",
   250→        color: "#111113",
   251→        backgroundColor: "#fafaf9",
   252→        border: "1px solid #e8e8e5",
   253→        whiteSpace: "nowrap",
   254→        cursor: tracking ? "wait" : "pointer",
   255→      }}
   256→    >
   257→      <ProviderIcon className="h-3 w-3" style={{ color: "#6b7280" }} />
   258→      <span>{item.full_name}</span>
   259→      <Star className="h-3 w-3" style={{ color: "#e8601a" }} />
   260→      <span style={{ color: "#6b7280", fontSize: "11px" }}>
   261→        {formatStars(item.stars)}
   262→      </span>
   263→      {tracking ? (
   264→        <Loader2
   265→          className="h-3 w-3 animate-spin"
   266→          style={{ color: "#e8601a" }}
   267→        />
   268→      ) : (
   269→        <Plus className="h-3 w-3" style={{ color: "#e8601a" }} />
   270→      )}
   271→    </button>
   272→  );
   273→}
