   160→// DockerHub handles GET /discover/dockerhub — searches Docker Hub repositories.
   161→func (h *DiscoverHandler) DockerHub(w http.ResponseWriter, r *http.Request) {
   162→	q := r.URL.Query().Get("q")
   163→	if q == "" {
   164→		q = "nginx"
   165→	}
   166→
   167→	cacheKey := fmt.Sprintf("dockerhub:%s", q)
   168→	if items, ok := h.getCached(cacheKey); ok {
   169→		RespondJSON(w, r, http.StatusOK, items)
   170→		return
   171→	}
   172→
   173→	u, _ := url.Parse(h.dockerHubURL + "/v2/search/repositories/")
   174→	params := url.Values{}
   175→	params.Set("query", q)
   176→	params.Set("page_size", "25")
   177→	u.RawQuery = params.Encode()
   178→
   179→	req, err := http.NewRequestWithContext(r.Context(), http.MethodGet, u.String(), nil)
   180→	if err != nil {
   181→		RespondError(w, r, http.StatusInternalServerError, "request_error", "failed to build Docker Hub request")
   182→		return
   183→	}
   184→	resp, err := h.client.Do(req)
   185→	if err != nil {
   186→		RespondError(w, r, http.StatusBadGateway, "upstream_error", "failed to reach Docker Hub API")
   187→		return
   188→	}
   189→	defer resp.Body.Close()
   190→
   191→	if resp.StatusCode != http.StatusOK {
   192→		RespondError(w, r, http.StatusBadGateway, "upstream_error", fmt.Sprintf("Docker Hub API returned %d", resp.StatusCode))
   193→		return
   194→	}
   195→
   196→	var dhResp struct {
