    15→  github_id: number;
    16→  github_login: string;
    17→  name?: string;
    18→  avatar_url?: string;
    19→}
    20→
    21→interface AuthContextValue {
    22→  user: User | null;
    23→  loading: boolean;
    24→  logout: () => Promise<void>;
    25→}
    26→
    27→const AuthContext = createContext<AuthContextValue>({
    28→  user: null,
    29→  loading: true,
    30→  logout: async () => {},
    31→});
    32→
    33→export function useAuth() {
    34→  return useContext(AuthContext);
    35→}
    36→
    37→export function AuthProvider({ children }: { children: ReactNode }) {
    38→  const [user, setUser] = useState<User | null>(null);
    39→  const [loading, setLoading] = useState(true);
    40→  const pathname = usePathname();
    41→  const router = useRouter();
    42→  const didFetch = useRef(false);
    43→
    44→  useEffect(() => {
    45→    if (didFetch.current) return;
    46→    didFetch.current = true;
    47→
    48→    fetch("/auth/me")
    49→      .then((res) => {
    50→        if (res.ok) return res.json();
    51→        throw new Error("unauthorized");
    52→      })
    53→      .then((data) => {
    54→        setUser(data);
    55→        setLoading(false);
    56→      })
    57→      .catch(() => {
    58→        setUser(null);
    59→        setLoading(false);
    60→      });
    61→  }, []);
    62→
    63→  // Redirect to /login when not authenticated and not already on /login
    64→  useEffect(() => {
    65→    if (!loading && !user && pathname !== "/login") {
    66→      router.replace("/login");
    67→    }
    68→  }, [loading, user, pathname, router]);
    69→
    70→  const logout = async () => {
    71→    await fetch("/auth/logout", { method: "POST" });
    72→    setUser(null);
    73→    router.replace("/login");
    74→  };
    75→
    76→  if (loading) {
    77→    return (
    78→      <div className="flex h-screen items-center justify-center bg-[#f8f8f6]">
    79→        <div className="h-6 w-6 animate-spin rounded-full border-2 border-[#e8601a] border-t-transparent" />
    80→      </div>
    81→    );
    82→  }
    83→
    84→  // On login page, render without redirect guard
    85→  if (pathname === "/login") {
    86→    return (
    87→      <AuthContext.Provider value={{ user, loading, logout }}>
    88→        {children}
    89→      </AuthContext.Provider>
    90→    );
    91→  }
    92→
    93→  // Not logged in and not on login page — handled by useEffect redirect above
    94→  if (!user) {
    95→    return null;
    96→  }
    97→
    98→  return (
    99→    <AuthContext.Provider value={{ user, loading, logout }}>
   100→      {children}
   101→    </AuthContext.Provider>
   102→  );
   103→}
