   145→// FetchReleases handles POST /sources/{id}/poll — polls upstream for new
   146→// releases, ingests them, and updates last_polled_at.
   147→func (h *SourcesHandler) FetchReleases(w http.ResponseWriter, r *http.Request) {
   148→	id := r.PathValue("id")
   149→	if id == "" {
   150→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
   151→		return
   152→	}
   153→	src, err := h.store.GetSource(r.Context(), id)
   154→	if err != nil {
   155→		RespondError(w, r, http.StatusNotFound, "not_found", "Source not found")
   156→		return
   157→	}
   158→
   159→	ingestionSrc := ingestion.BuildSource(h.httpClient, src.ID, src.Provider, src.Repository)
   160→	if ingestionSrc == nil {
   161→		RespondError(w, r, http.StatusUnprocessableEntity, "unsupported_provider", "Unsupported provider: "+src.Provider)
   162→		return
   163→	}
   164→
   165→	results, err := ingestionSrc.FetchNewReleases(r.Context())
   166→	if err != nil {
   167→		slog.Error("fetch releases failed", "source", src.ID, "err", err)
   168→		_ = h.store.UpdateSourcePollStatus(r.Context(), src.ID, err)
   169→		RespondError(w, r, http.StatusBadGateway, "upstream_error", "Failed to fetch releases from upstream")
   170→		return
   171→	}
   172→
   173→	_ = h.store.UpdateSourcePollStatus(r.Context(), src.ID, nil)
   174→
   175→	newCount := 0
   176→	if len(results) > 0 && h.ingestionService != nil {
   177→		for _, result := range results {
   178→			if procErr := h.ingestionService.ProcessResults(r.Context(), src.ID, src.Provider, []ingestion.IngestionResult{result}); procErr != nil {
   179→				slog.Error("process release failed", "source", src.ID, "version", result.RawVersion, "err", procErr)
   180→				continue
   181→			}
   182→			newCount++
   183→		}
   184→	}
   185→
   186→	RespondJSON(w, r, http.StatusOK, map[string]int{"new_releases": newCount})
   187→}
   188→
   189→// pollSourceAsync polls a source in the background and updates its poll status.
   190→func (h *SourcesHandler) pollSourceAsync(sourceID, provider, repository string) {
   191→	ctx := context.Background()
   192→
   193→	ingestionSrc := ingestion.BuildSource(h.httpClient, sourceID, provider, repository)
   194→	if ingestionSrc == nil {
   195→		slog.Warn("async poll: unsupported provider", "source", sourceID, "provider", provider)
   196→		return
   197→	}
   198→
   199→	slog.Info("async poll triggered", "source", sourceID, "provider", provider, "repository", repository)
   200→
   201→	results, err := ingestionSrc.FetchNewReleases(ctx)
   202→	if err != nil {
   203→		slog.Error("async poll failed", "source", sourceID, "err", err)
   204→		_ = h.store.UpdateSourcePollStatus(ctx, sourceID, err)
   205→		return
   206→	}
   207→
   208→	_ = h.store.UpdateSourcePollStatus(ctx, sourceID, nil)
   209→
   210→	if len(results) > 0 && h.ingestionService != nil {
   211→		for _, result := range results {
   212→			if procErr := h.ingestionService.ProcessResults(ctx, sourceID, provider, []ingestion.IngestionResult{result}); procErr != nil {
   213→				slog.Error("async poll: process release failed", "source", sourceID, "version", result.RawVersion, "err", procErr)
   214→			}
   215→		}
   216→	}
   217→}
