    12→
    13→// SourcesStore defines the persistence operations for sources.
    14→type SourcesStore interface {
    15→	ListSourcesByProject(ctx context.Context, projectID string, page, perPage int) ([]models.Source, int, error)
    16→	CreateSource(ctx context.Context, src *models.Source) error
    17→	GetSource(ctx context.Context, id string) (*models.Source, error)
    18→	UpdateSource(ctx context.Context, id string, src *models.Source) error
    19→	DeleteSource(ctx context.Context, id string) error
    20→	UpdateSourcePollStatus(ctx context.Context, id string, pollErr error) error
    21→}
    22→
    23→// SourcesHandler implements HTTP handlers for the /sources resource.
    24→type SourcesHandler struct {
    25→	store            SourcesStore
    26→	ingestionService *ingestion.Service
    27→	httpClient       *http.Client
    28→}
    29→
    30→// NewSourcesHandler returns a new SourcesHandler.
    31→func NewSourcesHandler(store SourcesStore, ingestionService *ingestion.Service, httpClient *http.Client) *SourcesHandler {
    32→	return &SourcesHandler{store: store, ingestionService: ingestionService, httpClient: httpClient}
    33→}
    34→
    35→// List handles GET /projects/{projectId}/sources — returns a paginated list of sources for a project.
    36→func (h *SourcesHandler) List(w http.ResponseWriter, r *http.Request) {
    37→	projectID := r.PathValue("projectId")
    38→	if projectID == "" {
    39→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    40→		return
    41→	}
    42→	page, perPage := ParsePagination(r)
    43→	sources, total, err := h.store.ListSourcesByProject(r.Context(), projectID, page, perPage)
    44→	if err != nil {
    45→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list sources")
    46→		return
    47→	}
    48→	if sources == nil {
    49→		sources = []models.Source{}
    50→	}
    51→	RespondList(w, r, http.StatusOK, sources, page, perPage, total)
    52→}
    53→
    54→// Create handles POST /projects/{projectId}/sources — creates a new source under a project.
    55→func (h *SourcesHandler) Create(w http.ResponseWriter, r *http.Request) {
    56→	projectID := r.PathValue("projectId")
    57→	if projectID == "" {
    58→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    59→		return
    60→	}
    61→	var src models.Source
    62→	if err := DecodeJSON(r, &src); err != nil {
    63→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    64→		return
    65→	}
    66→	src.ProjectID = projectID
    67→	src.Provider = strings.TrimSpace(src.Provider)
    68→	src.Repository = strings.TrimSpace(src.Repository)
    69→	if src.Provider == "" {
    70→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "provider is required")
    71→		return
    72→	}
    73→	if src.Repository == "" {
    74→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "repository is required")
    75→		return
    76→	}
    77→	if err := h.store.CreateSource(r.Context(), &src); err != nil {
    78→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create source")
    79→		return
    80→	}
    81→	go h.pollSourceAsync(src.ID, src.Provider, src.Repository)
    82→	RespondJSON(w, r, http.StatusCreated, src)
    83→}
    84→
    85→// Get handles GET /sources/{id} — returns a single source.
    86→func (h *SourcesHandler) Get(w http.ResponseWriter, r *http.Request) {
    87→	id := r.PathValue("id")
    88→	if id == "" {
    89→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
    90→		return
    91→	}
    92→	src, err := h.store.GetSource(r.Context(), id)
    93→	if err != nil {
    94→		RespondError(w, r, http.StatusNotFound, "not_found", "Source not found")
    95→		return
    96→	}
    97→	RespondJSON(w, r, http.StatusOK, src)
    98→}
    99→
   100→// Update handles PUT /sources/{id} — updates an existing source.
