	}
	if got.Data[0].Tracked {
		t.Error("expected org/cool-repo to not be tracked")
	}
	if !got.Data[1].Tracked {
		t.Error("expected already/tracked to be tracked")
	}
}

func TestSuggestionsStarsNoUser(t *testing.T) {
